import { createTheme } from '@mui/material/styles';

const theme = createTheme({
  palette: {
    mode: 'dark',
    primary: {
      main: '#7bd1ff',
      contrastText: '#04203a',
    },
    secondary: {
      main: '#76e8d0',
    },
    error: {
      main: '#ff6b7a',
    },
    text: {
      primary: '#f2f8ff',
      secondary: '#d0e0ef',
    },
    background: {
      default: '#071321',
      paper: 'rgba(13, 30, 48, 0.82)',
    },
  },
  typography: {
    fontFamily: '"Avenir Next", "Segoe UI", "Trebuchet MS", sans-serif',
    h4: {
      letterSpacing: 0.2,
    },
    h6: {
      letterSpacing: 0.2,
    },
  },
  shape: {
    borderRadius: 14,
  },
  components: {
    MuiCssBaseline: {
      styleOverrides: {
        body: {
          backgroundColor: '#071321',
          color: '#f2f8ff',
        },
      },
    },
    MuiPaper: {
      styleOverrides: {
        root: {
          border: '1px solid rgba(166, 210, 245, 0.26)',
          backdropFilter: 'blur(14px)',
          WebkitBackdropFilter: 'blur(14px)',
        },
      },
    },
    MuiCard: {
      styleOverrides: {
        root: {
          boxShadow: '0 18px 40px rgba(2, 8, 20, 0.45)',
          border: '1px solid rgba(166, 210, 245, 0.26)',
        },
      },
    },
    MuiTextField: {
      styleOverrides: {
        root: {
          '& .MuiOutlinedInput-root': {
            background: 'rgba(4, 20, 35, 0.75)',
            color: '#f2f8ff',
            '& fieldset': {
              borderColor: 'rgba(166, 210, 245, 0.34)',
            },
            '&:hover fieldset': {
              borderColor: 'rgba(166, 210, 245, 0.5)',
            },
          },
          '& .MuiInputLabel-root': {
            color: '#d0e0ef',
          },
        },
      },
    },
    MuiSelect: {
      styleOverrides: {
        select: {
          color: '#f2f8ff',
        },
      },
    },
    MuiChip: {
      styleOverrides: {
        root: {
          backgroundColor: 'rgba(8, 26, 44, 0.86)',
          color: '#f2f8ff',
        },
      },
    },
    MuiDialog: {
      styleOverrides: {
        paper: {
          background: 'linear-gradient(130deg, rgba(12, 36, 60, 0.95), rgba(8, 24, 41, 0.94))',
          border: '1px solid rgba(166, 210, 245, 0.24)',
        },
      },
    },
  },
});

export default theme;
